import { 神將身, 武拳, 執植臂, 叉腰臂 } from './shinsho.js';
export const 迷企羅 = (bi) => 神將身(bi, {
    臂(bi, 筆) {
        const { M, L, C, Qk, S, 衣, 細 } = 筆;
        // 鉾：長杆植岩，廣葉之刃在頂
        衣(() => {
            M(15.9, 96.6);
            L(15.9, 6.2);
            S();
            M(16.8, 96.6);
            L(16.8, 6.2);
            S();
            M(15.9, 96.6);
            Qk(16.35, 97.3, 16.8, 96.6);
            S(); // 石突
            M(15.65, 6.2);
            L(17.05, 6.2);
            S(); // 節
            M(15.7, 5.45);
            L(17.0, 5.45);
            S();
            // 廣葉：雙緣抱脊，收於一鋒
            M(16.35, 5.2);
            C(15.05, 4.1, 14.85, 1.1, 16.35, -2.7);
            S();
            M(16.35, 5.2);
            C(17.65, 4.1, 17.85, 1.1, 16.35, -2.7);
            S();
            細(() => { M(16.35, 4.5); L(16.35, -1.7); S(); });
        });
        // 左臂探杆（蔽內建），拳握之；右叉腰
        const { 拳 } = 執植臂(bi, 筆, 1);
        武拳(bi, 筆, 拳[0], 拳[1], { 轉: Math.PI / 2, 鏡: -1 });
        叉腰臂(bi, 筆, -1);
    },
    冠識(bi, 筆) {
        // 酉冠小識：冠距之雞——三距冠・喙
        const { M, L, Qk, S, 細 } = 筆;
        細(() => bi.dim(0.8, () => {
            M(-0.55, 8.1);
            L(-0.75, 7.35);
            S();
            M(0, 7.95);
            L(0, 7.15);
            S();
            M(0.55, 8.1);
            L(0.75, 7.35);
            S();
            M(-0.7, 8.6);
            Qk(0, 8.15, 0.7, 8.6);
            S();
            M(-0.2, 8.9);
            L(0, 9.4);
            S();
            M(0.2, 8.9);
            L(0, 9.4);
            S();
        }));
    },
});
